import type { Metadata } from "next";
import Link from "next/link";
import { redirect } from "next/navigation";
import Sidebar from "@/util/sidebar";
import { createSupabaseServerClient } from "@/lib/supabase/server-client";

export const metadata: Metadata = {
  title: "Dashboard • DispatchNow",
};

type ProfileRow = {
  id: string;
  username: string | null;
  tier: number | null;
};

type ReportRow = {
  id: string;
  type: string | null;
  status: string | null;
  created_at: string | null;
};

type IncidentRow = {
  id: string;
  title: string | null;
  status: string | null;
  priority: string | null;
  created_at: string | null;
};

function Pill({
  text,
  tone = "neutral",
}: {
  text: string;
  tone?: "neutral" | "red" | "green" | "orange";
}) {
  const cls =
    tone === "red"
      ? "bg-[#8B000D] text-white border-white/10"
      : tone === "green"
        ? "bg-white/5 text-[#34D399] border-white/10"
        : tone === "orange"
          ? "bg-white/5 text-[#FF9F1A] border-white/10"
          : "bg-white/5 text-white border-white/10";

  return (
    <span className={`inline-flex items-center rounded-full border px-3 py-1 text-[11px] ${cls}`}>
      {text}
    </span>
  );
}

function GhostButton({ href, children }: { href: string; children: React.ReactNode }) {
  return (
    <Link
      href={href}
      className="inline-flex items-center justify-center rounded-full border border-white/10 bg-white/5 px-3 py-2 text-[11px] text-white hover:bg-white/10 transition"
    >
      {children}
    </Link>
  );
}

function RedButton({ href, children }: { href: string; children: React.ReactNode }) {
  return (
    <Link
      href={href}
      className="inline-flex items-center justify-center rounded-full border border-white/10 bg-[#8B000D] px-3 py-2 text-[11px] text-white hover:brightness-110 transition"
    >
      {children}
    </Link>
  );
}

function formatDateShort(iso: string | null | undefined) {
  if (!iso) return "—";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return "—";
  return d.toLocaleString(undefined, {
    month: "short",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function Panel({
  title,
  right,
  children,
  className,
}: {
  title: string;
  right?: React.ReactNode;
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <section
      className={[
        "rounded-2xl border border-white/10 bg-white/5 backdrop-blur-md",
        "shadow-[0_10px_30px_rgba(0,0,0,0.35)]",
        className ?? "",
      ].join(" ")}
    >
      <div className="flex items-center justify-between gap-3 px-4 pt-3">
        <div className="text-sm font-semibold text-[#D9D9D9]">{title}</div>
        {right ? <div className="shrink-0">{right}</div> : null}
      </div>
      <div className="mt-3 h-px bg-white/10" />
      <div className="px-4 pb-4">{children}</div>
    </section>
  );
}

function RowCard({
  title,
  sub,
  right,
}: {
  title: string;
  sub?: React.ReactNode;
  right?: React.ReactNode;
}) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/5 px-4 py-3">
      <div className="flex items-start justify-between gap-3">
        <div className="min-w-0">
          <div className="truncate text-sm font-semibold text-[#D9D9D9]">{title}</div>
          {sub ? <div className="mt-1 text-xs text-[#D9D9D9]/60">{sub}</div> : null}
        </div>
        {right ? <div className="shrink-0">{right}</div> : null}
      </div>
    </div>
  );
}

function StatBox({ value, label }: { value: number | string; label: string }) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-center">
      <div className="text-base font-extrabold text-[#D9D9D9]">{value}</div>
      <div className="mt-1 text-[11px] text-[#D9D9D9]/60">{label}</div>
    </div>
  );
}

export default async function CitizenDashboardPage() {
  const supabase = await createSupabaseServerClient();

  const { data: userRes } = await supabase.auth.getUser();
  if (!userRes?.user) redirect("/");

  const user = userRes.user;

  const { data: profile } = await supabase
    .from("profiles")
    .select("id,username,tier")
    .eq("id", user.id)
    .maybeSingle<ProfileRow>();

  const username = profile?.username ?? "user";
  const tier = (profile?.tier ?? 1) as 1 | 2 | 3;

  if (tier !== 1) redirect("/dashboard");

  const { data: reports } = await supabase
    .from("reports")
    .select("id,type,status,created_at")
    .eq("user_id", user.id)
    .order("created_at", { ascending: false })
    .limit(3)
    .returns<ReportRow[]>();

  const { data: incidents } = await supabase
    .from("incidents")
    .select("id,title,status,priority,created_at")
    .eq("created_by", user.id)
    .order("created_at", { ascending: false })
    .limit(2)
    .returns<IncidentRow[]>();

  const sidebarWidth = 84;

  return (
    <main className="h-screen overflow-hidden bg-[#0b0b0c] text-[#D9D9D9]">
      <Sidebar activeHref="/dashboard" />

      <div
        className="h-full px-4 py-4"
        style={{ paddingLeft: `calc(${sidebarWidth}px + 16px)` }}
      >
        <div className="mx-auto grid h-full max-w-5xl grid-rows-[auto,1fr] gap-3">
          <header className="flex items-start justify-between gap-3">
            <div className="min-w-0">
              <div className="text-[11px] text-[#D9D9D9]/55">Citizen dashboard</div>
              <div className="mt-1 flex items-baseline gap-2">
                <div className="truncate text-2xl font-bold leading-none">My Activity</div>
                <div className="text-xs text-[#D9D9D9]/60">@{username}</div>
              </div>
              <div className="mt-2">
                <Pill text="Citizen" tone="green" />
              </div>
            </div>

            <div className="flex items-center gap-2">
              <GhostButton href={`/profile/${username}`}>View Profile</GhostButton>
              <RedButton href="/report/new">Create Report</RedButton>
            </div>
          </header>

          <div className="min-h-0 grid grid-cols-1 gap-3 lg:grid-cols-3">
            {/* LEFT */}
            <div className="min-h-0 grid grid-rows-[auto,1fr] gap-3">
              <Panel title="Quick Actions" right={<Pill text="Shortcuts" />}>
                <div className="space-y-2">
                  <RowCard
                    title="Create a new report"
                    sub="Submit flooding, outage, hazard, etc."
                    right={<RedButton href="/report/new">Create</RedButton>}
                  />
                  <RowCard
                    title="Browse incident catalog"
                    sub="See what’s active near you."
                    right={<GhostButton href="/incidents-catalog">Open</GhostButton>}
                  />
                  <RowCard
                    title="Browse reports catalog"
                    sub="Explore recent community reports."
                    right={<GhostButton href="/reports-catalog">Open</GhostButton>}
                  />
                </div>
              </Panel>

              <Panel title="Status">
                <div className="grid grid-cols-3 gap-2">
                  <StatBox value={(reports ?? []).length} label="My reports" />
                  <StatBox value={(incidents ?? []).length} label="My incidents" />
                  <StatBox value="—" label="Requests" />
                </div>
              </Panel>
            </div>

            {/* MIDDLE */}
            <div className="min-h-0">
              <Panel title="My Reports" right={<GhostButton href="/reports-catalog">See all</GhostButton>} className="h-full">
                <div className="space-y-2">
                  {(reports ?? []).map((r) => (
                    <RowCard
                      key={r.id}
                      title={r.type ?? "Report"}
                      sub={
                        <div className="flex items-center gap-2">
                          <span>{formatDateShort(r.created_at)}</span>
                          <span className="text-[#D9D9D9]/35">•</span>
                          <span className="text-[#D9D9D9]/70">{r.status ?? "—"}</span>
                        </div>
                      }
                      right={<GhostButton href={`/report/${r.id}`}>View</GhostButton>}
                    />
                  ))}

                  {(reports ?? []).length === 0 ? (
                    <div className="rounded-2xl border border-white/10 bg-white/5 p-4 text-sm text-[#D9D9D9]/70">
                      No reports yet.
                      <div className="mt-3">
                        <RedButton href="/report/new">Create Report</RedButton>
                      </div>
                    </div>
                  ) : null}
                </div>
              </Panel>
            </div>

            {/* RIGHT */}
            <div className="min-h-0 grid grid-rows-[1fr,auto] gap-3">
              <Panel title="My Incidents" right={<GhostButton href="/incidents-catalog">See all</GhostButton>} className="min-h-0">
                <div className="space-y-2">
                  {(incidents ?? []).map((i) => (
                    <RowCard
                      key={i.id}
                      title={i.title ?? "Incident"}
                      sub={
                        <div className="flex items-center gap-2">
                          <span>{formatDateShort(i.created_at)}</span>
                          <span className="text-[#D9D9D9]/35">•</span>
                          <span className="text-[#34D399]">{i.status ?? "—"}</span>
                          {i.priority ? (
                            <>
                              <span className="text-[#D9D9D9]/35">•</span>
                              <span className="text-[#D9D9D9]/70">{i.priority}</span>
                            </>
                          ) : null}
                        </div>
                      }
                      right={<GhostButton href={`/incident/${i.id}`}>View</GhostButton>}
                    />
                  ))}

                  {(incidents ?? []).length === 0 ? (
                    <div className="rounded-2xl border border-white/10 bg-white/5 p-4 text-sm text-[#D9D9D9]/70">
                      No incidents created by you yet.
                    </div>
                  ) : null}
                </div>
              </Panel>

              <section className="rounded-2xl border border-white/10 bg-white/5 px-4 py-3 text-center text-[11px] text-[#D9D9D9]/50">
                DispatchNow • citizen dashboard
              </section>
            </div>
          </div>
        </div>
      </div>
    </main>
  );
}